/* ─── Animated counter hook ─────────────────────────────────────── */
function useCounter(target, duration = 1.6, inView) {
  const [val, setVal] = useState(0);
  const done = useRef(false);
  useEffect(() => {
    if (!inView || done.current) return;
    done.current = true;
    const ctrl = animate(0, target, {
      duration,
      ease: 'easeOut',
      onUpdate: v => setVal(Math.floor(v)),
    });
    return () => ctrl.stop();
  }, [inView, target, duration]);
  return val;
}

/* ─── SVG Cable-pulley machine ───────────────────────────────────── */
function CableMachine({ progress }) {
  // progress: 0..1  →  handle goes from top to bottom
  const handleY = 20 + progress * 110;
  const weightY = 130 - progress * 110;
  const ropeLen1 = handleY - 20;
  const ropeLen2 = 130 - weightY;

  return (
    <svg
      viewBox="0 0 160 220"
      className="w-full h-full"
      style={{ filter: 'drop-shadow(0 0 18px rgba(56,189,248,0.25))' }}
    >
      {/* Frame uprights */}
      <rect x="20" y="10" width="6" height="200" rx="3" fill="#1e3a4a" />
      <rect x="134" y="10" width="6" height="200" rx="3" fill="#1e3a4a" />
      {/* Top crossbar */}
      <rect x="20" y="10" width="120" height="6" rx="3" fill="#1e3a4a" />
      {/* Top pulley */}
      <circle cx="80" cy="17" r="9" fill="none" stroke="#38bdf8" strokeWidth="2.5" />
      <circle cx="80" cy="17" r="3.5" fill="#38bdf8" />

      {/* Rope from weight to pulley */}
      <line x1="80" y1="17" x2="80" y2={weightY} stroke="#64b5f6" strokeWidth="1.8" strokeDasharray="3 2" />
      {/* Rope from pulley to handle */}
      <line x1="80" y1="17" x2="80" y2={handleY} stroke="#64b5f6" strokeWidth="1.8" strokeDasharray="3 2" />

      {/* Weight stack */}
      {[0, 1, 2, 3].map(i => (
        <rect
          key={i}
          x="62"
          y={weightY - i * 8}
          width="36"
          height="7"
          rx="2"
          fill={i === 0 ? '#38bdf8' : '#1a3a4f'}
          stroke="#38bdf8"
          strokeWidth="0.8"
          opacity={i === 0 ? 1 : 0.7 - i * 0.1}
        />
      ))}
      {/* Weight pin */}
      <rect x="78" y={weightY - 30} width="4" height="35" rx="2" fill="#64b5f6" opacity="0.6" />

      {/* Handle / bar */}
      <rect x="55" y={handleY} width="50" height="7" rx="3.5" fill="#90caf9" />
      {/* Hand grips */}
      <rect x="55" y={handleY - 2} width="12" height="11" rx="3" fill="#38bdf8" opacity="0.6" />
      <rect x="93" y={handleY - 2} width="12" height="11" rx="3" fill="#38bdf8" opacity="0.6" />

      {/* Bottom base */}
      <rect x="14" y="205" width="132" height="8" rx="4" fill="#1e3a4a" />
    </svg>
  );
}

