/* ─── Stat card with counter ─────────────────────────────────────── */
function StatCard({ value, label, suffix = '+', delay = 0 }) {
  const ref = useRef(null);
  const inView = useInView(ref, { once: true, margin: '-60px' });
  const num = useCounter(parseInt(value), 1.8, inView);
  return (
    <motion.div
      ref={ref}
      initial={{ opacity: 0, y: 30 }}
      animate={inView ? { opacity: 1, y: 0 } : {}}
      transition={{ duration: 0.6, delay }}
      className="text-center"
    >
      <div className="gym-font text-5xl md:text-6xl gradient-text mb-1">
        {num}{suffix}
      </div>
      <div className="text-gray-400 text-sm tracking-wide">{label}</div>
    </motion.div>
  );
}

